mapper.select:
SELECT DISTINCT u.id, u.username, u.password, u.phone, u.email, u.avatar, u.status, u.create_time, u.update_time, u.deleted FROM sys_user u LEFT JOIN sys_user_role ur ON u.id = ur.user_id LEFT JOIN sys_role r ON ur.role_id = r.id AND r.deleted = false WHERE u.deleted = false
AND u.username LIKE CONCAT('%', #{username}, '%')
AND u.phone LIKE CONCAT('%', #{phone}, '%')
AND u.status = #{status}
AND r.role_code = #{roleCode}
ORDER BY u.create_time DESC

SELECT COUNT(DISTINCT u.id) FROM sys_user u LEFT JOIN sys_user_role ur ON u.id = ur.user_id LEFT JOIN sys_role r ON ur.role_id = r.id AND r.deleted = false WHERE u.deleted = false
AND u.username LIKE CONCAT('%', #{username}, '%')
AND u.phone LIKE CONCAT('%', #{phone}, '%')
AND u.status = #{status}
AND r.role_code = #{roleCode}
